import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Router } from '@angular/router';
import { ProductService } from '../../services/product.service';

@Component({
  selector: 'app-add-product',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './add-product.html',
  styleUrl: './add-product.css',
})
export class AddProductComponent {
  name: string = '';
  price: number | null = null;
  description: string = '';
  quantity: number | null = null;
  successMessage: string = '';
  errorMessage: string = '';

  constructor(
    private productService: ProductService,
    private router: Router
  ) {}

  addProduct(): void {
    if (this.isFormValid()) {
      const newProduct = {
        name: this.name,
        price: this.price as number,
        description: this.description,
        quantity: this.quantity as number,
      };

      this.productService.addProduct(newProduct);
      this.router.navigate(['/']);
    } else {
      this.showErrorMessage();
    }
  }

  isFormValid(): boolean {
    return (
      this.name.trim() !== '' &&
      this.price !== null &&
      this.price > 0 &&
      this.description.trim() !== '' &&
      this.quantity !== null &&
      this.quantity > 0
    );
  }

  cancel(): void {
    this.router.navigate(['/']);
  }

  showSuccessMessage(): void {
    this.successMessage = 'Product added successfully!';
    this.errorMessage = '';
  }

  showErrorMessage(): void {
    this.errorMessage = 'Please fill in all fields with valid values.';
    this.successMessage = '';
  }
}
<div class="min-h-screen bg-gradient-to-br from-pink-50 to-purple-50 py-8 px-4">
  <div class="max-w-2xl mx-auto">
    <!-- Header -->
    <h2 class="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-pink-600 to-purple-600 mb-8">Add New Product</h2>
    
    <!-- Success Message -->
    <div *ngIf="successMessage" class="mb-6 p-4 bg-green-100 border border-green-400 text-green-700 rounded-lg">
      {{ successMessage }}
    </div>
    
    <!-- Error Message -->
    <div *ngIf="errorMessage" class="mb-6 p-4 bg-red-100 border border-red-400 text-red-700 rounded-lg">
      {{ errorMessage }}
    </div>

    <!-- Form -->
    <form (ngSubmit)="addProduct()" class="bg-white rounded-lg shadow-2xl p-8 border border-pink-200">
      <!-- Product Name -->
      <div class="mb-6">
        <label for="name" class="block text-pink-600 font-bold mb-2">Product Name *</label>
        <input 
          type="text" 
          id="name" 
          [(ngModel)]="name" 
          name="name"
          placeholder="Enter product name"
          required
          class="w-full px-4 py-2 border border-pink-300 rounded-lg bg-pink-50 text-gray-800 placeholder-gray-400 focus:outline-none focus:border-pink-500 focus:ring-1 focus:ring-pink-500 transition"
        />
      </div>

      <!-- Price -->
      <div class="mb-6">
        <label for="price" class="block text-pink-600 font-bold mb-2">Price *</label>
        <input 
          type="number" 
          id="price" 
          [(ngModel)]="price" 
          name="price"
          placeholder="Enter product price"
          step="0.01"
          required
          class="w-full px-4 py-2 border border-pink-300 rounded-lg bg-pink-50 text-gray-800 placeholder-gray-400 focus:outline-none focus:border-pink-500 focus:ring-1 focus:ring-pink-500 transition"
        />
      </div>

      <!-- Description -->
      <div class="mb-6">
        <label for="description" class="block text-pink-600 font-bold mb-2">Description *</label>
        <textarea 
          id="description" 
          [(ngModel)]="description" 
          name="description"
          placeholder="Enter product description"
          rows="4"
          required
          class="w-full px-4 py-2 border border-pink-300 rounded-lg bg-pink-50 text-gray-800 placeholder-gray-400 focus:outline-none focus:border-pink-500 focus:ring-1 focus:ring-pink-500 transition"
        ></textarea>
      </div>

      <!-- Quantity -->
      <div class="mb-8">
        <label for="quantity" class="block text-pink-600 font-bold mb-2">Quantity *</label>
        <input 
          type="number" 
          id="quantity" 
          [(ngModel)]="quantity" 
          name="quantity"
          placeholder="Enter product quantity"
          required
          class="w-full px-4 py-2 border border-pink-300 rounded-lg bg-pink-50 text-gray-800 placeholder-gray-400 focus:outline-none focus:border-pink-500 focus:ring-1 focus:ring-pink-500 transition"
        />
      </div>

      <!-- Buttons -->
      <div class="flex space-x-4">
        <button 
          type="submit" 
          class="flex-1 bg-gradient-to-r from-pink-500 to-rose-500 hover:from-pink-600 hover:to-rose-600 text-white font-bold py-3 rounded-lg transition duration-200 shadow-lg hover:shadow-xl"
        >
          Add Product
        </button>
        <button 
          type="button" 
          (click)="cancel()"
          class="flex-1 bg-gradient-to-r from-gray-300 to-gray-400 hover:from-gray-400 hover:to-gray-500 text-gray-800 font-bold py-3 rounded-lg transition duration-200"
        >
          Cancel
        </button>
      </div>
    </form>
  </div>
</div>
